import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.Arrays;
import java.util.List;

@Controller
public class LogoutController {

    private static final List<String> ALLOWED_REDIRECTS = Arrays.asList(
            "/home",
            "/login",
            "/goodbye"
    );

    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response,
                       @RequestParam(value = "next", required = false) String next) throws IOException {
        // Perform logout logic here

        if (isValidRedirect(next)) {
            response.sendRedirect(next);
        } else {
            response.sendRedirect("/home"); // Default redirect
        }
    }

    private boolean isValidRedirect(String next) {
        return next != null && ALLOWED_REDIRECTS.contains(next);
    }
}